 * Исправленная удача, индикаторы статусов и гипер-детальный лог.
 */

const DC_SCOPE = "world";
const DC_KEY = "beer_furious_v12";
const DC_ACTION = "beer_furious_act_v12";
const DEFAULT_IMG = "icons/svg/mystery-man.svg";
const FLASK_ICON = "icons/consumables/potions/potion-bottle-corked-fancy-red.webp";

const TECHNIQUES = {
