    dip: { name: "Дипломатия", skill: "diplomacy", icon: "fa-comments", s: "Вы и враг -1 ОО.", f: "Цель допинга +1 Допинг." },
    itm: { name: "Запугивание", skill: "intimidation", icon: "fa-angry", s: "Ваш 1 ОО -> Врагу.", f: "Враг 1 ОО -> Вам." },
    per: { name: "Выступление", skill: "performance", icon: "fa-guitar", s: "+2 Допинга.", f: "Потеря всех Допингов." },
