    sur: { name: "Выживание", skill: "survival", icon: "fa-campground", s: "Лимит ОО +1.", f: "Лимит ОО -1." },
    crf: { name: "Ремесло", skill: "crafting", icon: "fa-hammer", s: "Ваш след. допинг на себя: КС -3.", f: "Допинг врага на вас: КС +3." },
    prc: { name: "Внимательность", skill: "perception", icon: "fa-search", s: "Враг: Неудача (2d20 худший).", f: "Вы: Неудача." },
    lor: { name: "Alcohol-Lore", skill: "lore", icon: "fa-beer", s: "-1 ОО и +1 Допинг.", f: "Сивуха! +2 ОО к итогу." }
};

const FLAVOR = {
    ath: { s: ["{n} пьет залпом, напрягая жилы!", "{n} демонстрирует мощь атлета."], f: ["{n} давится напитком.", "{n} не справляется с весом кружки."] },
    acr: { s: ["{n} выпивает, стоя на руках!", "{n} ловит ритм глотка."], f: ["{n} спотыкается о чужую ногу.", "{n} неловко задевает стол."] },
    thi: { s: ["{n} подливает мути в чужую кружку.", "{n} меняет стаканы местами."], f: ["{n} пойман за руку!", "Рука {n} дрогнула."] },
    ste: { s: ["{n} пьет абсолютно незаметно.", "{n} скрывает хмель в глазах."], f: ["{n} громко икает.", "{n} проливает эль на рубаху."] },
    arc: { s: ["Глаза {n} светятся магией удачи.", "{n} заколдовал напиток."], f: ["Заклятие {n} ударило ему в нос.", "Магия {n} развеялась."] },
    occ: { s: ["{n} шепчет защитное заклятье.", "{n} чертит знак на пене."], f: ["{n} видит чудищ в кружке.", "Шепот сбивает {n} с толку."] },
    rel: { s: ["{n} благословлен богами хмеля.", "Молитва защищает нутро {n}."], f: ["Боги отвернулись от {n}.", "Вера {n} пошатнулась."] },
    nat: { s: ["{n} зажевал глоток корнем.", "{n} пьет как лесной зверь."], f: ["{n} спутал корень с поганкой.", "У {n} аллергия на солод."] },
    soc: { s: ["{n} толкает великий тост.", "{n} очаровывает трактир."], f: ["Тост {n} звучит глупо.", "{n} оскорбляет бармена."] },
    dec: { s: ["{n} виртуозно симулирует глоток.", "{n} лжет о своей трезвости."], f: ["{n} запнулся на вранье.", "Блеф {n} не удался."] },
    dip: { s: ["{n} пьет за дружбу.", "{n} сглаживает углы."], f: ["Слова {n} только злят врагов.", "{n} запутался в уговорах."] },
    itm: { s: ["{n} пугает всех своим оскалом.", "{n} впечатал кулак в стол."], f: ["Рык {n} звучит жалко.", "Над {n} просто смеются."] },
    per: { s: ["{n} запел удалую песню.", "Трактир рукоплещет {n}!"], f: ["{n} путает слова и ноты.", "{n} освистан толпой."] },
    med: { s: ["{n} знает, как очистить кровь.", "{n} пьет профессионально."], f: ["{n} перепутал микстуры.", "Медицина бессильна у {n}."] },
    sur: { s: ["Для {n} это пиво — просто вода.", "{n} привык к ядам."], f: ["Организм {n} изношен.", "{n} не выдерживает темпа."] },
    crf: { s: ["{n} улучшил свою кружку.", "{n} пьет с расчетом."], f: ["Кружка {n} треснула.", "{n} ошибся в расчетах."] },
    prc: { s: ["{n} видит каждое движение.", "{n} следит за руками."], f: ["Мир {n} поплыл перед глазами.", "{n} моргнул не вовремя."] },
    lor: { s: ["{n} узнает букет эля.", "{n} ценит этот сорт."], f: ["«Это сивуха!» — орет {n}.", "{n} давится дегтем."] }
};

const ROUND_RULES = {
    1: { baseOO: { s: 0, f: 1 }, dcAdd: 0 },
    2: { baseOO: { s: 1, f: 2 }, dcAdd: 3 },
    3: { baseOO: { s: 2, f: 3 }, dcAdd: 6 }
};

const PF2E_DC = [14, 15, 16, 18, 19, 20, 22, 23, 24, 26, 27, 28, 30, 31, 32, 34, 35, 36, 38, 39, 40, 42, 44, 46, 48, 50];

if (!Handlebars.helpers.dcEq) Handlebars.registerHelper('dcEq', (a, b) => String(a) === String(b));
if (!Handlebars.helpers.dcAnd) Handlebars.registerHelper('dcAnd', (a, b) => !!(a && b));
if (!Handlebars.helpers.dcOr) Handlebars.registerHelper('dcOr', (a, b) => !!(a || b));
if (!Handlebars.helpers.dcNot) Handlebars.registerHelper('dcNot', (a) => !a);

// === ЯДРО ГМ ===
window.dcProcessAction = async function(data) {
    if (!game.user.isGM) return;
    let state = foundry.utils.deepClone(canvas.scene.getFlag(DC_SCOPE, DC_KEY) || { players: {}, round: 1, phase: 'join', log: [], debug: false });
    let changed = false;

    if (data.action === "join") {
        if (state.players[data.actorId]) { state.players[data.actorId].isParticipating = data.val; changed = true; }
    } else if (data.action === "sig") {
        if (state.players[data.actorId]) { state.players[data.actorId].signature = data.val; changed = true; }
    } else if (data.action === "select") {
        if (state.players[data.actorId]) { state.players[data.actorId].selectedTech = data.val; changed = true; }
    } else if (data.action === "confirm") {
        if (state.players[data.actorId]) { state.players[data.actorId].isConfirmed = true; changed = true; }
    } else if (data.action === "debug") {
        state.debug = data.val; changed = true;
    } else if (data.action === "doping") {
        let p = state.players[data.actorId];
        let target = state.players[data.targetId];
        if (p && p.doping > 0 && target && !target.isEliminated) {
            p.doping--;
            p.lastDopingTarget = data.targetId;
            let power = p.nextDopingPower || 1;
            if (target.dopingEffectX2 && data.targetId !== data.actorId) power = 2;
            if (target.isDopingImmune && data.targetId !== data.actorId) {
                state.log.unshift(`<div style="color:#ff4444; font-size:10px;">🛡️ <b>${target.name}</b> иммунен к внешнему допингу!</div>`);
            } else {
                let mod = data.targetId === data.actorId ? -power : power;
                target.currentDCMod = (target.currentDCMod || 0) + mod;
                state.log.unshift(`<div style="color:#ffaa00; font-size:11px;">🧪 <b>${p.name}</b> влил допинг в <b>${target.name}</b> (${mod > 0 ? '+' : ''}${mod} КС).</div>`);
            }
            changed = true;
        }
    } else if (data.action === "next") {
        if (state.phase === 'join') { 
            state.phase = 'play'; state.round = 1; setupRound(state); 
        } else if (state.phase === 'play') {
            await processRound(state);
            checkEliminations(state);
            if (state.round < 3 && !checkWinner(state)) { state.round++; setupRound(state); } 
            else { state.phase = 'results'; finalizeGame(state); }
        } else if (state.phase === 'results') {
            for (let id in state.players) {
                let p = state.players[id];
                p.oo = 0; p.doping = 1; p.isConfirmed = false; p.selectedTech = ""; p.hand = []; 
                p.currentDCMod = 0; p.permDCMod = 0; p.nextRoundEffects = {}; p.isEliminated = false;
            }
            state.phase = 'join'; state.round = 1; state.log = ["--- Стол очищен ---"];
        }
        changed = true;
    } else if (data.action === "reset") {
        await canvas.scene.unsetFlag(DC_SCOPE, DC_KEY);
        // Не закрываем окно, но отправляем сигнал сброса
        await canvas.scene.setFlag(DC_SCOPE, DC_KEY, { players: {}, round: 1, phase: 'join', log: [], debug: false, sync: Date.now() });
        return;
    }

    if (changed) { state.sync = Date.now(); await canvas.scene.setFlag(DC_SCOPE, DC_KEY, state); }
};

function setupRound(state) {
    const rules = ROUND_RULES[state.round];
    const activePlayers = Object.values(state.players).filter(p => p.isParticipating && !p.isEliminated);
    const maxLvl = activePlayers.length > 0 ? Math.max(...activePlayers.map(p => p.level || 0)) : 1;
    const baseDC = PF2E_DC[maxLvl] + rules.dcAdd;

    state.log.unshift(`<div style="text-align:center; background:#4a2c11; color:#ffd700; padding:6px; margin:10px 0; border:2px solid #d4af37; font-weight:bold; font-size:14px; box-shadow: 0 0 8px black; text-transform:uppercase;">🍻 РАУНД ${state.round} (Базовый КС ${baseDC}) 🍻</div>`);

    for (let id in state.players) {
        let p = state.players[id];
        if (!p.isParticipating || p.isEliminated) { p.hand = []; continue; }
        p.isConfirmed = false; p.selectedTech = ""; p.currentDCMod = 0; p.isDopingImmune = false;

        let pool = Object.keys(TECHNIQUES);
        let handCount = p.nextRoundEffects?.handSize ?? 3;
        let hand = [];

        if ((state.round === 1 || state.round === 3) && p.signature && handCount > 0) {
            hand.push(p.signature); pool = pool.filter(t => t !== p.signature);
        }
        while (hand.length < handCount) {
            let r = pool[Math.floor(Math.random() * pool.length)];
            hand.push(r); pool = pool.filter(t => t !== r);
        }
        p.hand = hand;
        if (handCount === 1) p.selectedTech = hand[0];
    }
}

async function processRound(state) {
    const rules = ROUND_RULES[state.round];
    const activePlayers = Object.values(state.players).filter(p => p.isParticipating && !p.isEliminated);
    const maxLvl = activePlayers.length > 0 ? Math.max(...activePlayers.map(p => p.level || 0)) : 1;
    const baseDC = PF2E_DC[maxLvl] + rules.dcAdd;
    let activeIds = Object.keys(state.players).filter(id => state.players[id].isParticipating && !state.players[id].isEliminated);

    for (let id of activeIds) {
        let p = state.players[id];
        const actor = game.actors.get(id);
        const techKey = p.selectedTech || (p.hand.length > 0 ? p.hand[0] : 'ath');
        const tech = TECHNIQUES[techKey];
        const skillMod = (tech.skill === "perception" ? actor.perception?.mod : (actor.skills?.[tech.skill]?.mod || 0)) || 0;

        let dcCalc = `База ${baseDC}`;
        if (p.permDCMod) dcCalc += p.permDCMod > 0 ? ` +${p.permDCMod}(Рел)` : ` ${p.permDCMod}(Рел)`;
        if (p.currentDCMod) dcCalc += p.currentDCMod > 0 ? ` +${p.currentDCMod}(Доп)` : ` ${p.currentDCMod}(Доп)`;
        if (p.nextRoundEffects?.dcMod) dcCalc += p.nextRoundEffects.dcMod > 0 ? ` +${p.nextRoundEffects.dcMod}(Атл)` : ` ${p.nextRoundEffects.dcMod}(Атл)`;

        let finalDC = baseDC + (p.permDCMod || 0) + (p.currentDCMod || 0) + (p.nextRoundEffects?.dcMod || 0);
        let rollFormula = p.nextRoundEffects?.fortune ? "2d20kh" : (p.nextRoundEffects?.misfortune ? "2d20kl" : "1d20");
        let rType = p.nextRoundEffects?.fortune ? "УДАЧА" : (p.nextRoundEffects?.misfortune ? "НЕУДАЧА" : "Обычный");

        const roll = await new Roll(`${rollFormula} + ${skillMod}`).evaluate({async:true});
        const diceResults = roll.dice[0].results.map(r => r.result);
        const d20 = roll.total - skillMod;

        let success = 2;
        if (roll.total >= finalDC + 10) success = 4; else if (roll.total >= finalDC) success = 3; else if (roll.total <= finalDC - 10) success = 1;
        if (d20 === 20) success = Math.min(success + 1, 4); if (d20 === 1) success = Math.max(success - 1, 1);

        let baseGain = (success >= 3) ? rules.baseOO.s : rules.baseOO.f;
        let critMod = (success === 4) ? -2 : (success === 1 ? 1 : 0);
        let totalGain = Math.max(0, baseGain + critMod);

        let oldDop = p.doping;
        if (success === 4) p.doping++; if (success === 1) p.doping = Math.max(0, p.doping - 1);
        if (p.nextRoundEffects?.ooReduction) totalGain = Math.max(0, totalGain - 1);
        if (p.isLorePenalty) { totalGain += 2; p.isLorePenalty = false; }

        let oldOO = p.oo; p.oo += totalGain;

        // Клонируем старые эффекты для лога, а текущие очищаем
        let activeEffects = foundry.utils.deepClone(p.nextRoundEffects || {});
        p.nextRoundEffects = {}; p.nextDopingPower = 1;

        let validTargets = activeIds.filter(oid => oid !== id);
        let randOpp = validTargets[Math.floor(Math.random() * validTargets.length)];
        let s = (success >= 3);
        let tLog = "";
        const fList = FLAVOR[techKey][s ? 's' : 'f'];
        const fTxt = fList[Math.floor(Math.random() * fList.length)].replace("{n}", `<b style="color:white;">${p.name}</b>`);

        switch(techKey) {
            case 'ath': if(s) p.nextRoundEffects.dcMod = -2; else p.nextRoundEffects.dcMod = 2; break;
            case 'acr': if(s) { if(randOpp) state.players[randOpp].nextRoundEffects.handSize = 2; tLog = `Враг ${state.players[randOpp].name}: -1 карта.`; } else p.nextRoundEffects.handSize = 2; break;
            case 'thi': if(s) { if(randOpp) { state.players[randOpp].oo += 1; tLog = `${state.players[randOpp].name} +1 ОО.`; } } else p.oo += 1; break;
            case 'ste': if(s) p.isDopingImmune = true; else p.dopingEffectX2 = true; break;
            case 'arc': if(s) p.nextRoundEffects.fortune = true; else if(randOpp) { state.players[randOpp].nextRoundEffects.fortune = true; tLog = `${state.players[randOpp].name} +Удача.`; } break;
            case 'occ': if(s) p.nextRoundEffects.ooReduction = true; else p.nextRoundEffects.handSize = 1; break;
            case 'rel': if(s) p.permDCMod -= 1; else p.permDCMod += 1; break;
            case 'nat': if(s) p.oo = Math.max(0, p.oo - 1); else p.oo += 1; break;
            case 'soc': if(s) { activeIds.forEach(oid => { if(oid !== id) state.players[oid].nextRoundEffects.dcMod = 1; }); tLog = "Всем врагам КС +1."; } else p.nextRoundEffects.dcMod = 2; break;
            case 'dec': if(s) { if(randOpp) { state.players[randOpp].doping = Math.max(0, state.players[randOpp].doping - 1); tLog = `${state.players[randOpp].name} -1 допинг.`; } } else p.doping = Math.max(0, p.doping - 1); break;
            case 'dip': if(s) { p.oo = Math.max(0, p.oo - 1); if(randOpp) state.players[randOpp].oo = Math.max(0, state.players[randOpp].oo - 1); } 
                        else { if(p.lastDopingTarget) state.players[p.lastDopingTarget].doping++; } break;
            case 'itm': if(s) { if(randOpp && p.oo > 0) { p.oo--; state.players[randOpp].oo++; tLog = `Передал 1 ОО врагу ${state.players[randOpp].name}.`; } } 
                        else { if(randOpp && state.players[randOpp].oo > 0) { state.players[randOpp].oo--; p.oo++; tLog = `Забрал 1 ОО у ${state.players[randOpp].name}.`; } } break;
            case 'per': if(s) p.doping += 2; else p.doping = 0; break;
            case 'med': if(s) p.oo = Math.max(0, p.oo - 1); else p.oo += 1; break;
            case 'sur': if(s) p.limit += 1; else p.limit = Math.max(1, p.limit - 1); break;
            case 'crf': if(s) p.nextDopingPower = 3; else p.nextDopingPower = -3; break;
            case 'prc': if(s) { if(randOpp) state.players[randOpp].nextRoundEffects.misfortune = true; tLog = `${state.players[randOpp].name} +Неудача.`; } else p.nextRoundEffects.misfortune = true; break;
            case 'lor': if(s) { p.oo = Math.max(0, p.oo - 1); p.doping++; } else p.isLorePenalty = true; break;
        }

        let resTxt = success === 4 ? "КРИТ. УСПЕХ" : success === 3 ? "УСПЕХ" : success === 2 ? "ПРОВАЛ" : "КРИТ. ПРОВАЛ";
        let resCol = success === 4 ? "#00ff00" : success === 3 ? "#2ecc71" : success === 2 ? "#e67e22" : "#ff4444";

        state.log.unshift(`
            <div style="border-left:4px solid ${resCol}; padding:8px; margin-bottom:10px; background:rgba(0,0,0,0.4); border-radius:4px; box-shadow: 0 2px 4px black;">
                <div style="display:flex; justify-content:space-between; font-weight:bold; border-bottom:1px solid #444; padding-bottom:3px; margin-bottom:5px;">
                    <span style="color:${resCol}">${p.name}</span>
                    <span style="color:#ffd700;"><i class="fas ${tech.icon}"></i> ${tech.name}</span>
                </div>
                <div style="font-size:11px; line-height:1.4; color:#eee;">
                    🎯 <b>${rType} Бросок:</b> [${diceResults.join(', ')}] ➔ <b>${d20}</b> + ${skillMod} = <b>${roll.total}</b> vs <b>КС ${finalDC}</b><br>
                    <small style="color:#888;">(${dcCalc})</small><br>
                    📈 <b>Итог:</b> <span style="color:${resCol}">${resTxt}</span> (+${totalGain} ОО)<br>
                    🍺 <b>Очки Опьянения:</b> ${oldOO} ➔ <b>${p.oo}</b> / ${p.limit}<br>
                    🧪 <b>Допинг:</b> ${oldDop} ➔ <b>${p.doping}</b>
                </div>
                <div style="font-size:10px; margin-top:5px; padding:4px; background:rgba(0,0,0,0.3); border-radius:3px; color:#ccaa88;">
                    ${fTxt}<br>
                    <span style="font-size:9px; opacity:0.8; font-style:italic;">${s ? tech.s : tech.f} ${tLog ? ' | ' + tLog : ''}</span>
                </div>
            </div>
        `);
    }
}

function checkEliminations(state) {
    for (let id in state.players) {
        let p = state.players[id];
        if (p.isParticipating && !p.isEliminated && p.oo >= p.limit) {
            p.isEliminated = true;
            state.log.unshift(`<div style="background:#500; color:white; text-align:center; padding:6px; border-radius:4px; margin:5px 0; font-weight:bold; border:1px solid red; box-shadow: 0 0 10px rgba(255,0,0,0.5);">💀 ${p.name} В ОТКЛЮЧКЕ (Лимит ${p.limit} ОО)!</div>`);
        }
    }
}

function checkWinner(state) {
    const alive = Object.values(state.players).filter(p => p.isParticipating && !p.isEliminated);
    return alive.length <= 1;
}

function finalizeGame(state) {
    const alive = Object.values(state.players).filter(p => p.isParticipating && !p.isEliminated);
    let winMsg = alive.length === 1 ? `🏆 ПОБЕДИТЕЛЬ: ${alive[0].name}!` : (alive.length === 0 ? `🍻 ВСЕ В ОТКЛЮЧКЕ! НИЧЬЯ!` : `🏆 ПОБЕДА ПО ОЧКАМ!`);
    state.log.unshift(`<div style="background:linear-gradient(90deg, #d4af37, #ffd700, #d4af37); color:black; text-align:center; padding:10px; border-radius:5px; margin:15px 0; font-weight:bold; font-size:16px; box-shadow:0 0 20px gold; text-transform:uppercase;">${winMsg}</div>`);
}

// === ИНТЕРФЕЙС ===
const dcStyle = `
<style>
  #dc-app { display: flex; flex-direction: row; background: #1a0f0a; color: #f4e1d2; font-family: 'Signika', sans-serif; height: 100%; border: 3px solid #5d3a24; overflow: hidden; position: relative;}
  #dc-app.is-dragging-doping .dc-card:not(.eliminated) { cursor: crosshair; border: 2px dashed #ffd700 !important; animation: dc-pulse 1s infinite; }
  @keyframes dc-pulse { 0% { box-shadow: 0 0 5px gold; } 50% { box-shadow: 0 0 15px gold; } 100% { box-shadow: 0 0 5px gold; } }
  .dc-col-rules { flex: 0.9; background: #2b1d16; padding: 12px; font-size: 11px; border-right: 2px solid #5d3a24; overflow-y: auto; color: #ccaa88; }
  .dc-col-main { flex: 2.8; padding: 15px; padding-bottom: 60px; overflow-y: auto; background: radial-gradient(circle, #3d2b1f 0%, #1a0f0a 100%); }
  .dc-col-log { flex: 2.2; background: #000; padding: 12px; font-size: 11px; overflow-y: auto; border-left: 2px solid #5d3a24; color: #ccaa88; }
  .dc-header { background: #d4af37; color: #1a0f0a; text-align: center; padding: 10px; font-weight: bold; text-transform: uppercase; font-size: 20px; margin: -15px -15px 15px -15px; box-shadow: 0 4px 10px black; letter-spacing: 2px; border-bottom: 2px solid #5d3a24;}
  .dc-card { background: rgba(0, 0, 0, 0.4); border: 1px solid #5d3a24; border-radius: 8px; padding: 10px; margin-bottom: 12px; border-left: 5px solid #5d3a24; transition: 0.2s; position: relative;}
  .dc-card.confirmed { border-left-color: #2ecc71; background: rgba(46, 204, 113, 0.05); }
  .dc-card.eliminated { filter: grayscale(1); opacity: 0.4; }
  .dc-oo-bar { height: 12px; background: #000; border-radius: 6px; margin-top: 5px; border: 1px solid #5d3a24; overflow: hidden; }
  .dc-oo-fill { height: 100%; background: linear-gradient(90deg, #ffd700, #ff8800); transition: width 0.5s; }
  .dc-tech-card { width: 95px; text-align: center; background: #2b1d16; border: 1px solid #5d3a24; padding: 8px; border-radius: 5px; cursor: pointer; font-size: 10px; position: relative;}
  .dc-tech-card.selected { background: #d4af37; color: #1a0f0a; font-weight: bold; box-shadow: 0 0 8px #ffd700; }
  .dc-tech-card i { display: block; font-size: 20px; margin-bottom: 4px; }
  .dc-status-badge { display: inline-block; padding: 2px 8px; border-radius: 4px; font-weight: bold; font-size: 10px; margin-right: 10px; box-shadow: 0 0 5px black; }
  .dc-status-badge.fortune { background: #d4af37; color: #1a0f0a; border: 1px solid #fff; }
  .dc-status-badge.misfortune { background: #502d6d; color: #fff; border: 1px solid #ff00ff; }
  .dc-sig-select { background: #3d2b1f !important; color: #ffd700 !important; border: 1px solid #d4af37 !important; border-radius: 3px; font-family: 'Signika', sans-serif; height: 24px; outline: none; padding: 0 5px; font-size: 11px;}
  .dc-sig-select option { background: #3d2b1f; color: #ffd700; }
  .dc-footer { position: absolute; bottom: 0; left: 0; width: 100%; height: 44px; background: #000; border-top: 2px solid #d4af37; display: flex; align-items: center; padding: 0 20px; z-index: 100; justify-content: space-between; }
  .dc-btn-main { background: #d4af37; color: #1a0f0a; border: 1px solid #fff; padding: 5px 25px; cursor: pointer; font-size: 14px; font-weight: bold; text-transform: uppercase; border-radius: 4px; min-width: 150px;}
  .dc-btn-main:hover { background: #ffd700; }
  .dc-btn-reset { background: #600; color: #fff; border: 1px solid red; padding: 5px 15px; cursor: pointer; font-size: 11px; font-weight: bold; border-radius: 4px;}
  .dc-btn-reset:hover { background: red; }
  body.dc-doping-cursor { cursor: url("${FLASK_ICON}") 16 16, crosshair !important; }
  body.dc-doping-cursor * { cursor: url("${FLASK_ICON}") 16 16, crosshair !important; }
</style>
`;

const dcTemplate = `
<div id="dc-app" class="{{#if state.isDraggingDoping}}is-dragging-doping{{/if}}">
  <div class="dc-col-rules">
    <h3 style="color:#d4af37; border-bottom:1px solid #d4af37; margin-bottom:8px;">📜 ПРАВИЛА</h3>
    <p><b>Р1:</b> 0/1 ОО | <b>Р2:</b> 1/2 ОО | <b>Р3:</b> 2/3 ОО</p>
    <p><b>ЛИМИТ:</b> Тел × 2.</p>
    <hr>
    <p style="font-size:10px; color:#ffd700;"><b>ДОПИНГ (🧪):</b> Клик на флакон -> Клик на цель.</p>
  </div>

  <div class="dc-col-main">
    <div class="dc-header">🍺 ХМЕЛЬНОЙ ФОРСАЖ 🍺</div>
    {{#each players}}
    <div class="dc-card {{#if this.isConfirmed}}confirmed{{/if}} {{#if this.isEliminated}}eliminated{{/if}}" data-actor="{{this.id}}">
      <div style="display:flex; align-items:center; gap:12px; pointer-events:none;">
        <img src="{{this.img}}" width="44" height="44" style="border-radius:4px; border:2px solid #d4af37;">
        <div style="flex-grow:1;">
          <div style="display:flex; justify-content:space-between; align-items:baseline;">
            <b style="font-size:15px; color:#ffd700;">{{this.name}} {{#if this.isEliminated}}(В ОТКЛЮЧКЕ){{/if}}</b>
            <span style="font-size:11px;"><b>{{this.oo}}</b> / {{this.limit}} ОО</span>
          </div>
          <div class="dc-oo-bar"><div class="dc-oo-fill" style="width:{{this.ooPct}}%;"></div></div>
        </div>
        {{#if (dcAnd ../isPlayPhase (dcAnd (dcOr this.isOwner (dcAnd ../isGM ../state.debug)) (dcNot this.isEliminated)))}}
           <div style="position:relative; cursor:pointer; pointer-events:auto;" class="dc-flask-btn" data-actor="{{this.id}}">
             <i class="fas fa-flask" style="font-size:26px; color:#ff8800; filter:drop-shadow(0 0 2px black);"></i>
             <span style="position:absolute; top:-8px; right:-8px; background:red; color:white; border-radius:10px; padding:1px 5px; font-size:10px; font-weight:bold; border:1px solid white;">{{this.doping}}</span>
           </div>
        {{/if}}
      </div>

      {{#if (dcAnd ../isPlayPhase (dcNot this.isEliminated))}}
        {{#if (dcOr this.isOwner (dcAnd ../isGM ../state.debug))}}
            {{#if this.isConfirmed}}
                <div style="text-align:center; color:#2ecc71; margin-top:10px; font-weight:bold; text-transform:uppercase; font-size:12px;"><i class="fas fa-check-circle"></i> {{this.selName}}</div>
            {{else}}
                <div style="display:flex; align-items:center; justify-content:center; margin-top:10px; gap:5px;">
                  <div style="display:flex; flex-direction:column; gap:5px;">
                    {{#if this.nextRoundEffects.fortune}} <div class="dc-status-badge fortune">🌟 УДАЧА</div> {{/if}}
                    {{#if this.nextRoundEffects.misfortune}} <div class="dc-status-badge misfortune">💀 НЕУДАЧА</div> {{/if}}
                  </div>
                  {{#each this.displayHand}}
                    <div class="dc-tech-card {{#if this.sel}}selected{{/if}}" data-actor="{{../id}}" data-tech="{{this.id}}">
                      <span style="position:absolute; top:-5px; right:-5px; background:#4a2c11; color:gold; font-size:9px; padding:1px 4px; border-radius:4px; border:1px solid gold;">+{{this.mod}}</span>
                      <i class="fas {{this.icon}}"></i> {{this.name}}
                    </div>
                  {{/each}}
                </div>
                {{#if this.selectedTech}}
                    <div style="margin-top:10px; font-size:10px; background:rgba(0,0,0,0.5); padding:10px; border-radius:4px; border:1px dashed #d4af37;">
                        <div style="color:#2ecc71;"><b>Успех:</b> {{this.selS}}</div>
                        <div style="color:#e67e22; margin-top:4px;"><b>Провал:</b> {{this.selF}}</div>
                        {{#if this.isOwner}}
                            <button class="dc-btn-confirm-action" style="margin-top:10px; width:100%; background:#1e4d2b; color:#00ff00; border:2px solid #00ff00; cursor:pointer; height:28px; font-size:12px; font-weight:bold; text-transform:uppercase;" data-actor="{{this.id}}">ПОДТВЕРДИТЬ ВЫБОР</button>
                        {{/if}}
                    </div>
                {{/if}}
            {{/if}}
        {{else}}
            <div style="text-align:center; margin-top:10px; font-style:italic; opacity:0.6;">Игрок выбирает стратегию...</div>
        {{/if}}
      {{/if}}

      {{#if (dcAnd ../isJoinPhase this.isOwner)}}
        <div style="margin-top:10px; font-size:11px; display:flex; align-items:center; gap:10px; background:rgba(0,0,0,0.2); padding:5px; border-radius:4px;">
          <span>Коронная:</span>
          <select class="dc-sig-select" data-actor="{{this.id}}">
            <option value="">-- Нет --</option>
            {{#each ../techList}}<option value="{{@key}}" {{#if (dcEq ../signature @key)}}selected{{/if}}>{{this.name}}</option>{{/each}}
          </select>
          <label style="cursor:pointer; margin-left:auto;"><input type="checkbox" class="dc-join-cb" data-actor="{{this.id}}" {{#if this.isParticipating}}checked{{/if}}> В ИГРЕ</label>
        </div>
      {{/if}}
    </div>
    {{/each}}
  </div>

  <div class="dc-col-log">
    <h4 style="color:#d4af37; border-bottom:1px solid #3d2b1f; margin: 0 0 10px 0; text-align:center;">📜 ХРОНИКА</h4>
    {{#each state.log}}<div style="margin-bottom:8px; border-bottom:1px solid #222; padding-bottom:4px; line-height:1.2; font-size:11px;">{{{this}}}</div>{{/each}}
  </div>

  <div class="dc-footer">
    <div>
      {{#if isGM}}
        <label style="font-size:11px; color:#aaa; cursor:pointer; display:flex; align-items:center; gap:5px;">
          <input type="checkbox" id="dc-debug-check" {{#if state.debug}}checked{{/if}}> Отладка ГМ
        </label>
      {{/if}}
    </div>
    <div style="display:flex; align-items:center; gap:15px;">
      {{#if isGM}}
        <button class="dc-btn-main" id="dc-next-btn">
          {{#if (dcEq state.phase 'join')}}НАЧАТЬ{{/if}}
          {{#if (dcEq state.phase 'play')}}ПРОДОЛЖИТЬ{{/if}}
          {{#if (dcEq state.phase 'results')}}ОЧИСТИТЬ{{/if}}
        </button>
        <button class="dc-btn-reset" id="dc-reset-btn">СБРОС</button>
      {{/if}}
    </div>
  </div>
</div>
`;

class DrunkenCourageApp extends Application {
  static get defaultOptions() { return mergeObject(super.defaultOptions, { id: "dc-window-v12", title: "Хмельной Форсаж", width: 1250, height: 850, resizable: true, dragDrop: [{ dropSelector: "#dc-app" }] }); }

  _getState() { return canvas.scene.getFlag(DC_SCOPE, DC_KEY) || { players: {}, round: 1, phase: 'join', log: [], debug: false }; }

  getData() {
    const state = this._getState();
    const playersData = {};
    for (let [id, p] of Object.entries(state.players)) {
        let actor = game.actors.get(id);
        let ooPct = Math.min(100, (p.oo / (p.limit || 10)) * 100);
        let hand = (p.hand || []).map(tKey => {
            const t = TECHNIQUES[tKey];
            const mod = (t.skill === "perception" ? actor.perception?.mod : (actor.skills?.[t.skill]?.mod || 0)) || 0;
            return { ...t, id: tKey, sel: p.selectedTech === tKey, mod };
        });
        playersData[id] = { ...p, id, ooPct, img: actor?.img || DEFAULT_IMG, isOwner: actor?.isOwner, displayHand: hand, selS: (p.selectedTech ? TECHNIQUES[p.selectedTech].s : ""), selF: (p.selectedTech ? TECHNIQUES[p.selectedTech].f : ""), selName: (p.selectedTech ? TECHNIQUES[p.selectedTech].name : "") };
    }
    return { state, players: playersData, isGM: game.user.isGM, techList: TECHNIQUES, isJoinPhase: state.phase === 'join', isPlayPhase: state.phase === 'play', isResultsPhase: state.phase === 'results' };
  }

  activateListeners(html) {
    super.activateListeners(html);
    html.find('.dc-join-cb').change(ev => this._send({ action: "join", actorId: ev.currentTarget.dataset.actor, val: ev.currentTarget.checked }));
    html.find('.dc-sig-select').change(ev => this._send({ action: "sig", actorId: ev.currentTarget.dataset.actor, val: ev.target.value }));
    html.find('.dc-tech-card').click(ev => this._send({ action: "select", actorId: ev.currentTarget.dataset.actor, val: ev.currentTarget.dataset.tech }));
    html.find('.dc-btn-confirm-action').click(ev => this._send({ action: "confirm", actorId: ev.currentTarget.dataset.actor }));

    html.find('.dc-flask-btn').click(ev => {
        ev.stopPropagation();
        this.isDraggingDoping = true;
        this.dopingSource = ev.currentTarget.dataset.actor;
        $('body').addClass('dc-doping-cursor');
        ui.notifications.info("Допинг взят! Кликните по карточке участника.");
    });

    html.find('.dc-card').click(ev => {
        if (this.isDraggingDoping) {
            this._send({ action: "doping", actorId: this.dopingSource, targetId: ev.currentTarget.dataset.actor });
            this.isDraggingDoping = false;
            $('body').removeClass('dc-doping-cursor');
        }
    });

    if (game.user.isGM) {
        html.find('#dc-next-btn').click(() => this._send({ action: "next" }));
        html.find('#dc-reset-btn').click(() => this._send({ action: "reset" }));
        html.find('#dc-debug-check').change(ev => this._send({ action: "debug", val: ev.currentTarget.checked }));
    }
  }

  async _renderInner(data) { return $(dcStyle + Handlebars.compile(dcTemplate)(data)); }

  async _onDrop(event) {
    if (!game.user.isGM) return;
    const data = JSON.parse(event.dataTransfer.getData('text/plain'));
    if (data.type !== "Actor") return;
    let actor = await fromUuid(data.uuid);
    let state = this._getState();
    let con = actor.system.abilities?.con?.mod || 0;
    state.players[actor.id] = { name: actor.name, level: actor.level || 1, oo: 0, limit: Math.max(2, con * 2), doping: 1, signature: "", isParticipating: true, currentDCMod: 0, permDCMod: 0, hand: [], selectedTech: "", isConfirmed: false, nextRoundEffects: {}, isEliminated: false };
    await canvas.scene.setFlag(DC_SCOPE, DC_KEY, state);
  }

  async _send(data) {
    if (game.user.isGM) await window.dcProcessAction(data);
    else await game.user.setFlag(DC_SCOPE, DC_ACTION, { ...data, ts: Date.now() });
  }
}

if (!window.dcHookV12) {
    Hooks.on("updateUser", async (user, changes) => {
        if (!game.user.isGM) return;
        const f = changes.flags?.[DC_SCOPE]?.[DC_ACTION];
        if (f) { await window.dcProcessAction(f); await user.unsetFlag(DC_SCOPE, DC_ACTION); }
    });
    Hooks.on("updateScene", (scene, data) => {
        if (hasProperty(data, `flags.${DC_SCOPE}.${DC_KEY}`)) {
            Object.values(ui.windows).forEach(app => { if (app instanceof DrunkenCourageApp) app.render(false); });
        }
    });
    window.dcHookV12 = true;
}

new DrunkenCourageApp().render(true);
